private static int indexPositionBig(int[] data, int x, int min, int max) {
        int lx=data[min];
        int hx=data[max-1];
        if (x<=lx) {
            if (x==lx) return min;
            return -1;
        }
        if (x>=hx) {
            if (x==hx) return max-1;
            return -1;
        }

        while ((min+10)<max) {
            int mid = (int)((long)min+(((long)(max-min))*((long)(x-lx)))/(((long)(hx-lx))*2)); // best estimate of position
            int mx=data[mid];
            if (x==mx) return mid;
            if (x<mx) {
                max=mid;
                hx=mx;
            } else {
                min=mid+1;
                lx=mx;
            }
        }
        return indexPositionSmall(data, x,min,max);                
